import time

class Twitter:
    def __init__(self):
        """
        Twitter objesini başlatır.
        """
        # Tüm tweetleri depolar: tweet_id -> {'user_id': int, 'text': str, 'timestamp': float}
        self.tweets = {}
        # Bir sonraki tweet için kullanılacak benzersiz id
        self.next_tweet_id = 0

        # Takip ilişkilerini depolar: follower_id -> set of followee_ids
        self.follows = {}

        # Her kullanıcının attığı tweetleri depolar: user_id -> list of tweet_ids (kronolojik sırada)
        self.user_tweets_map = {}

    def postTweet(self, userId: int, tweetText: str) -> None:
        """
        Bir kullanıcının yeni bir tweet atmasını sağlar.
        """
        tweet_id = self.next_tweet_id
        self.next_tweet_id += 1
        timestamp = time.time()  # Tweetin atıldığı zamanı kaydeder

        self.tweets[tweet_id] = {
            'user_id': userId,
            'text': tweetText,
            'timestamp': timestamp
        }

        if userId not in self.user_tweets_map:
            self.user_tweets_map[userId] = []
        self.user_tweets_map[userId].append(tweet_id)

    def follow(self, followerId: int, followeeId: int) -> None:
        """
        Bir kullanıcının başka bir kullanıcıyı takip etmesini sağlar.
        """
        if followerId not in self.follows:
            self.follows[followerId] = set()
        self.follows[followerId].add(followeeId)

    def unfollow(self, followerId: int, followeeId: int) -> None:
        """
        Bir kullanıcının başka bir kullanıcıyı takibi bırakmasını sağlar.
        """
        if followerId in self.follows and followeeId in self.follows[followerId]:
            self.follows[followerId].remove(followeeId)

    def getNewsFeed(self, userId: int) -> list[dict]:
        """
        Belirtilen kullanıcının haber akışını döndürür.
        Haber akışı, kullanıcının kendi tweetleri ve takip ettiği kişilerin tweetlerinden oluşur,
        en yeniler en başta olacak şekilde sıralanır. En fazla 10 tweet döndürülür.
        """
        feed_tweet_ids = []

        # Kullanıcının kendi tweetlerini ekle
        if userId in self.user_tweets_map:
            feed_tweet_ids.extend(self.user_tweets_map[userId])

        # Takip edilen kullanıcıların tweetlerini ekle
        if userId in self.follows:
            for followee_id in self.follows[userId]:
                if followee_id in self.user_tweets_map:
                    feed_tweet_ids.extend(self.user_tweets_map[followee_id])

        # Toplanan tweet id'lerine karşılık gelen tweet nesnelerini al
        all_relevant_tweets = []
        for tweet_id in feed_tweet_ids:
            if tweet_id in self.tweets:
                all_relevant_tweets.append(self.tweets[tweet_id])

        # Tweetleri zaman damgasına göre azalan sırada sırala (en yeni en başta)
        all_relevant_tweets.sort(key=lambda tweet: tweet['timestamp'], reverse=True)

        # En fazla 10 tweet döndür
        return all_relevant_tweets[:10]
